function editAlertProfile(type){const form=byId('alert-profile-form');const profile=state.alertSettings.alerts.profiles[type]||{};form.elements.alertType.value=type;form.elements.enabled.checked=profile.enabled!==false;for(const input of form.querySelectorAll('input[name="platforms"]'))input.checked=(profile.platforms||[]).includes(input.value);form.elements.priority.value=profile.priority||'';form.elements.durationMs.value=profile.durationMs||'';form.elements.titleTemplate.value=profile.titleTemplate||'';form.elements.detailTemplate.value=profile.detailTemplate||'';form.elements.soundMode.value=profile.sound?.mode||'none';form.elements.soundVolume.value=profile.sound?.volume??0.35;form.elements.customSoundUrl.value=profile.sound?.customUrl||'';form.elements.cardBackgroundColor.value=profile.card?.backgroundColor||'#171120';form.elements.cardFontFamily.value=profile.card?.fontFamily||'system';form.elements.backgroundImageUrl.value=profile.card?.backgroundImageUrl||'';form.elements.aggregationMode.value=profile.aggregation?.mode||'none';form.elements.aggregationWindowMs.value=profile.aggregation?.windowMs||5000;form.classList.add('editing');form.scrollIntoView({behavior:'smooth',block:'start'});form.elements.titleTemplate.focus();byId('alert-state').textContent=`Editing ${type}. The form above now contains its saved settings.`}
