byId('reward-admin-form').addEventListener('submit',async(event)=>{event.preventDefault();const form=event.target;if(!form.checkValidity()){form.reportValidity();return}const data=new FormData(form);const platform=String(data.get('platform'));const operation=String(data.get('operation'));const rewardId=String(data.get('rewardId')||'').trim();const redemptionId=String(data.get('redemptionId')||'').trim();const status=byId('reward-admin-state');if((operation==='fulfill'||operation==='cancel')&&!redemptionId){status.textContent='Fulfill and cancel require the exact redemption ID.';return}if(!confirm(`Run Twitch reward operation "${operation}" on reward ${rewardId}? This changes the live reward in Streamer.bot.`))return;status.setAttribute('aria-busy','true');status.textContent='Requesting documented Twitch reward operation…';try{const result=await api('/wizard/api/rewards/administer',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({platform,operation,rewardId,...(redemptionId?{redemptionId}:{}),approvedByCreator:true})});status.textContent=result.available?`${result.operation} requested for reward ${result.rewardId}. Check Streamer.bot Action History to confirm completion.`:`Reward operation unavailable: ${result.error}`;if(result.available)form.reset()}catch(error){status.textContent=error.message}finally{status.removeAttribute('aria-busy')}});
